/* ── RATIONALE BOX ── */
.rationale {
  background: #fff;
  border: 1px solid #e5e7eb;
  border-left: 4px solid #c7000b;
  border-radius: 8px;
  padding: 18px 22px;
  margin-bottom: 24px;
  display: flex;
  gap: 16px;
  align-items: flex-start;
}
.rationale-icon {
  width: 32px;
  height: 32px;
  background: #fef2f2;
  border-radius: 6px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.rationale-icon svg { color: #c7000b; }
.rationale-tag {
  font-size: 10px;
  font-weight: 700;
  color: #c7000b;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  margin-bottom: 5px;
}
.rationale p {
  font-size: 13.5px;
  color: #374151;
  line-height: 1.75;
}
.rationale strong { color: #111827; }
.rationale em { color: #c7000b; font-style: normal; font-weight: 600; }

input.new_string:
/* ── UX INFO BUTTON + POPOVER ── */
.ux-info-wrap {
  position: absolute;
  top: 16px;
  right: 0;
  z-index: 10;
}
.option-panel { position: relative; }
.ux-info-btn {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 5px 11px;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 500;
  color: #6b7280;
  cursor: default;
  transition: border-color 0.15s, color 0.15s;
  font-family: inherit;
  user-select: none;
}
.ux-info-btn svg { flex-shrink: 0; }
.ux-info-wrap:hover .ux-info-btn {
  border-color: #c7000b;
  color: #c7000b;
}
.ux-popover {
  position: absolute;
  top: calc(100% + 8px);
  right: 0;
  width: 360px;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-left: 3px solid #c7000b;
  border-radius: 10px;
  padding: 16px 18px;
  box-shadow: 0 8px 24px rgba(0,0,0,0.10);
  opacity: 0;
  pointer-events: none;
  transform: translateY(-4px);
  transition: opacity 0.18s, transform 0.18s;
}
.ux-info-wrap:hover .ux-popover {
  opacity: 1;
  pointer-events: auto;
  transform: translateY(0);
}
.ux-popover-tag {
  font-size: 10px;
  font-weight: 700;
  color: #c7000b;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  margin-bottom: 7px;
}
.ux-popover p {
  font-size: 12.5px;
  color: #374151;
  line-height: 1.75;
}
.ux-popover strong { color: #111827; }
.ux-popover em { color: #c7000b; font-style: normal; font-weight: 600; }

