const dotClasses = ['td-r', 'td-y', 'td-y', 'td-g', 'td-g'];

function selectStep(idx) {
  for (let i = 0; i < 5; i++) {
    const dot = document.getElementById('tdot' + i);
    const label = document.getElementById('tlabel' + i);
    dot.className = 'tl-dot ' + dotClasses[i] + (i === idx ? ' active' : '');
    label.className = 'tl-step-name' + (i === idx ? ' active' : '');
  }
  const d = stepData[idx];
  document.getElementById('jtSummary').innerHTML = d.summary;
  const mg = document.getElementById('jtMetrics');
  mg.innerHTML = d.metrics.map(m =>
    `<div class="jt-mc"><div class="jt-ml">${m.label}</div><div class="jt-mv ${m.cls}">${m.val}</div></div>`
  ).join('');
  document.getElementById('jtEvidence').innerHTML = `
    <div class="iev">
      <div class="iev-label">大客户痛点</div>
      <div class="iev-pain">${d.pain}</div>
      <div class="iev-source">${d.painMeta}</div>

