  background: #fff; border: 1px solid #f0f0f0; border-radius: 6px; padding: 7px 10px;
}
.sg-label { font-size: 11px; color: #374151; font-weight: 500; min-width: 130px; }
.sg-bar { flex: 1; height: 4px; background: #f0f0f0; border-radius: 2px; overflow: hidden; }
.sg-fill { height: 100%; border-radius: 2px; }
.sg-fill.ok  { background: #22c55e; }
.sg-fill.warn { background: #f59e0b; }
.sg-fill.crit { background: #c7000b; }
.sg-val { font-size: 12px; font-weight: 700; min-width: 40px; text-align: right; }
.sg-val.ok { color: #15803d; } .sg-val.warn { color: #b45309; } .sg-val.crit { color: #c7000b; }
.sg-badge {
  font-size: 10px; font-weight: 700; padding: 2px 7px; border-radius: 8px;
  min-width: 32px; text-align: center;
}
.sg-badge.ok   { background: #f0fdf4; color: #15803d; }
.sg-badge.warn { background: #fffbeb; color: #b45309; }
.sg-badge.crit { background: #fef2f2; color: #c7000b; }

