const dotClasses = ['td-r', 'td-y', 'td-y', 'td-g', 'td-g'];

function renderMetrics(d) {
  if (d.metricType === 'status') {
    const statusLabel = { ok: '达标', warn: '警告', crit: '严重' };
    return `<div class="status-grid">${d.metrics.map(m => `
      <div class="sg-row">
        <span class="sg-label">${m.label}</span>
        <div class="sg-bar"><div class="sg-fill ${m.status}" style="width:${m.pct}%"></div></div>
        <span class="sg-val ${m.status}">${m.val}</span>
        <span class="sg-badge ${m.status}">${statusLabel[m.status]}</span>
      </div>`).join('')}</div>`;
  }
  return `<div class="jt-metrics">${d.metrics.map(m =>
    `<div class="jt-mc"><div class="jt-ml">${m.label}</div><div class="jt-mv ${m.cls}">${m.val}</div></div>`
  ).join('')}</div>`;
}

function selectStep(idx) {
  for (let i = 0; i < 5; i++) {
    const dot = document.getElementById('tdot' + i);
    const label = document.getElementById('tlabel' + i);
    dot.className = 'tl-dot ' + dotClasses[i] + (i === idx ? ' active' : '');
    label.className = 'tl-step-name' + (i === idx ? ' active' : '');
  }
  const d = stepData[idx];
  document.getElementById('jtSummary').innerHTML = d.summary;
  document.getElementById('jtMetrics').outerHTML = renderMetrics(d);
  document.getElementById('jtEvidence').innerHTML = `
    <div class="iev">
      <div class="iev-label">大客户痛点</div>
      <div class="iev-pain">${d.pain}</div>
      <div class="iev-source">${d.painMeta}</div>
    </div>
    <div class="iev">
      <div class="iev-label">VOD 原声</div>
      <div class="iev-vod">${d.vod}</div>
      <div class="iev-vod-meta">${d.vodMeta}</div>
      <div class="iev-vol">${d.vol}</div>
    </div>`;

