1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	<meta charset="UTF-8">
5	<title>CANN 体验看板 · 设计方案对比</title>
6	<link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
7	<style>
8	*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
9	body{font-family:'Inter',system-ui,sans-serif;background:#f4f5f8;color:#1a1a1a;min-height:100vh}
10	
11	/* ── HEADER ── */
12	.ph{background:#fff;border-bottom:1px solid #e5e7eb;padding:14px 40px;display:flex;align-items:center;gap:12px}
13	.ph-logo{font-size:15px;font-weight:700;color:#c7000b;letter-spacing:-.02em}
14	.ph-sep{color:#d1d5db;font-size:18px}
15	.ph-title{font-size:13px;color:#6b7280;font-weight:500}
16	
17	/* ── TABS ── */
18	.tabs{background:#fff;border-bottom:2px solid #e5e7eb;padding:0 40px;display:flex}
19	.tab{padding:13px 22px;font-size:13.5px;font-weight:500;color:#6b7280;border:none;background:none;cursor:pointer;border-bottom:3px solid transparent;margin-bottom:-2px;font-family:inherit;display:flex;align-items:center;gap:8px;transition:color .15s,border-color .15s}
20	.tab:hover{color:#374151}
21	.tab.on{color:#c7000b;border-bottom-color:#c7000b}
22	.tbadge{font-size:10px;font-weight:700;padding:2px 7px;border-radius:10px}
23	.tb-rec{background:#fef2f2;color:#c7000b}
24	.tb-alt{background:#eff6ff;color:#2563eb}
25	
26	/* ── PANEL ── */
27	.panel{display:none;padding:28px 40px;max-width:1300px;margin:0 auto;position:relative}
28	.panel.on{display:block}
29	
30	/* ── UX INFO ── */
31	.ux-wrap{position:absolute;top:28px;right:0;z-index:20}
32	.ux-btn{display:flex;align-items:center;gap:5px;padding:5px 11px;background:#fff;border:1px solid #e5e7eb;border-radius:20px;font-size:12px;font-weight:500;color:#6b7280;cursor:default;font-family:inherit;user-select:none;transition:all .15s}
33	.ux-wrap:hover .ux-btn{border-color:#c7000b;color:#c7000b}
34	.ux-pop{position:absolute;top:calc(100% + 8px);right:0;width:380px;background:#fff;border:1px solid #e5e7eb;border-left:3px solid #c7000b;border-radius:10px;padding:16px 18px;box-shadow:0 8px 24px rgba(0,0,0,.1);opacity:0;pointer-events:none;transform:translateY(-4px);transition:opacity .18s,transform .18s}
35	.ux-wrap:hover .ux-pop{opacity:1;pointer-events:auto;transform:translateY(0)}
36	.ux-tag{font-size:10px;font-weight:700;color:#c7000b;text-transform:uppercase;letter-spacing:.07em;margin-bottom:7px}
37	.ux-pop p{font-size:12.5px;color:#374151;line-height:1.75}
38	.ux-pop strong{color:#111827}
39	.ux-pop em{color:#c7000b;font-style:normal;font-weight:600}
40	
41	/* ── MOCKUP SHELL ── */
42	.mock{background:#fff;border:1px solid #e5e7eb;border-radius:12px;overflow:hidden;box-shadow:0 2px 10px rgba(0,0,0,.06)}
43	.chrome{background:#f3f4f6;border-bottom:1px solid #e5e7eb;padding:9px 16px;display:flex;align-items:center;gap:6px}
44	.dot{width:10px;height:10px;border-radius:50%}
45	.dot-r{background:#ef4444}.dot-y{background:#f59e0b}.dot-g{background:#22c55e}
46	.chrome-url{margin-left:10px;background:#fff;border:1px solid #d1d5db;border-radius:6px;padding:3px 12px;font-size:11px;color:#9ca3af;flex:1;max-width:360px}
47	
48	/* ── SHARED ATOMS ── */
49	.sec-label{font-size:10px;font-weight:700;color:#9ca3af;text-transform:uppercase;letter-spacing:.07em;margin-bottom:8px}
50	.badge{font-size:10px;font-weight:700;padding:2px 7px;border-radius:8px}
51	.b-r{background:#fef2f2;color:#c7000b}
52	.b-y{background:#fffbeb;color:#b45309}
53	.b-g{background:#f0fdf4;color:#15803d}
54	.b-gray{background:#f3f4f6;color:#6b7280}
55	.trend-up{color:#15803d;font-size:11px;font-weight:600}
56	.trend-dn{color:#c7000b;font-size:11px;font-weight:600}
57	.trend-flat{color:#9ca3af;font-size:11px}
58	
59	/* ════════════════════════════════════
60	   OPTION 1 — HEATMAP COMMAND CENTER
61	════════════════════════════════════ */
62	.hm-stats{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;padding:20px;border-bottom:1px solid #f0f0f0;background:#fafafa}
63	.hm-stat{background:#fff;border:1px solid #e5e7eb;border-radius:8px;padding:12px 16px}
64	.hm-stat-label{font-size:11px;color:#9ca3af;margin-bottom:4px}
65	.hm-stat-val{font-size:22px;font-weight:700;color:#1a1a1a}
66	.hm-stat-val span{font-size:12px;font-weight:400;color:#9ca3af;margin-left:3px}
67	.hm-stat-sub{font-size:11px;margin-top:2px}
68	
69	.hm-filters{padding:12px 20px;border-bottom:1px solid #f0f0f0;background:#fff;display:flex;align-items:center;gap:10px;flex-wrap:wrap}
70	.fl{font-size:11px;color:#9ca3af;font-weight:600}
71	.fchip{padding:4px 11px;border-radius:16px;font-size:11px;font-weight:500;border:1px solid #e5e7eb;background:#fff;color:#6b7280;cursor:pointer;transition:all .12s}
72	.fchip.on{background:#c7000b;color:#fff;border-color:#c7000b}
73	.fsep{width:1px;height:18px;background:#e5e7eb;margin:0 4px}
74	
75	.hm-body{display:flex}
76	.hm-left{flex:1;padding:20px;overflow-x:auto}
77	.hm-table{width:100%;border-collapse:collapse;min-width:600px}
78	.hm-table th{font-size:10px;color:#6b7280;font-weight:600;padding:8px 10px;text-align:center;background:#f9fafb;border:1px solid #eee}
79	.hm-table th:first-child{text-align:left;min-width:150px}
80	.hm-table th:last-child{background:#f0f4ff;color:#3730a3}
81	.hm-table td{border:1px solid #f0f0f0;padding:0}
82	.hm-table td:first-child{padding:10px 12px;font-size:12px;font-weight:500;color:#374151}
83	.hm-table tr:hover td{background:#fafafa}
84	.hm-table tr.sel td{background:#fef7f7}
85	.hm-table tr.sel td:first-child{border-left:3px solid #c7000b}
86	
87	.hcell{text-align:center;padding:6px 4px;cursor:pointer}
88	.hcell-inner{display:inline-flex;flex-direction:column;align-items:center;gap:2px}
89	.hcell-val{font-size:12px;font-weight:700;padding:4px 8px;border-radius:5px;min-width:48px}
90	.hc-r .hcell-val{background:#fef2f2;color:#c7000b}
91	.hc-y .hcell-val{background:#fffbeb;color:#b45309}
92	.hc-g .hcell-val{background:#f0fdf4;color:#15803d}
93	.hcell-trend{font-size:9px;font-weight:600}
94	.hc-r .hcell-trend{color:#c7000b}
95	.hc-y .hcell-trend{color:#b45309}
96	.hc-g .hcell-trend{color:#15803d}
97	.row-score{text-align:center;padding:6px 4px}
98	.rs-inner{display:flex;flex-direction:column;align-items:center;gap:3px}
