.pain-tags{display:flex;gap:4px;flex-wrap:wrap}
.pain-tag{font-size:9px;padding:1px 6px;border-radius:8px;font-weight:600}
.pt-status{background:#fffbeb;color:#b45309}
.pt-owner{background:#eff6ff;color:#2563eb}
.pt-cust{background:#faf5ff;color:#7c3aed}
.pain-progress{margin-top:4px;display:flex;align-items:center;gap:5px}
.pp-track{flex:1;height:3px;background:#f0f0f0;border-radius:2px;overflow:hidden}
.pp-fill{height:100%;border-radius:2px;background:#c7000b}
.pp-pct{font-size:9px;color:#9ca3af;min-width:24px}

.vod-item{margin-bottom:10px}
.vod-head{display:flex;align-items:center;gap:6px;margin-bottom:4px}
.vod-bar{flex:1;height:4px;background:#f0f0f0;border-radius:2px;overflow:hidden}
.vod-fill{height:100%;background:#c7000b;border-radius:2px}
.vod-vol{font-size:10px;font-weight:700;color:#c7000b;min-width:26px}
.vod-trend{font-size:9px;color:#c7000b;font-weight:600}
.vod-text{font-size:11px;color:#374151;line-height:1.55;border-left:2px solid #e5e7eb;padding-left:7px}
.vod-meta{font-size:9px;color:#9ca3af;margin-top:2px}

.funnel-section{margin-bottom:16px}
.funnel-row{display:flex;align-items:center;gap:10px;margin-bottom:5px}
.funnel-label{font-size:11px;color:#374151;font-weight:500;min-width:80px}
.funnel-track{flex:1;height:20px;background:#f0f0f0;border-radius:4px;overflow:hidden;position:relative}
.funnel-fill{height:100%;border-radius:4px;display:flex;align-items:center;justify-content:flex-end;padding-right:7px;transition:width .3s}
.funnel-fill-ok{background:linear-gradient(90deg,#86efac,#22c55e)}
.funnel-fill-warn{background:linear-gradient(90deg,#fde68a,#f59e0b)}
.funnel-fill-bad{background:linear-gradient(90deg,#fca5a5,#c7000b)}
.funnel-pct{font-size:10px;font-weight:700;color:#fff}
.funnel-drop{font-size:10px;color:#9ca3af;min-width:60px;text-align:right}

.journey-acc{border:1px solid #e5e7eb;border-radius:8px;overflow:hidden}
.ja-row{border-bottom:1px solid #f0f0f0;cursor:pointer}
.ja-row:last-child{border-bottom:none}
.ja-header{display:flex;align-items:center;gap:8px;padding:10px 13px;background:#fff;transition:background .1s}
.ja-header:hover{background:#fafafa}
.ja-num{width:20px;height:20px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;flex-shrink:0}
.jn-r{background:#fef2f2;color:#c7000b}.jn-y{background:#fffbeb;color:#b45309}.jn-g{background:#f0fdf4;color:#15803d}
.ja-name{font-size:12px;color:#374151;font-weight:500;flex:1}
.ja-right{display:flex;align-items:center;gap:8px}
.ja-time{font-size:10px;color:#9ca3af}
.ja-drop{font-size:10px;font-weight:600}
.ja-drop.bad{color:#c7000b}
.ja-body{display:none;padding:10px 13px 13px;background:#fafafa;border-top:1px solid #f0f0f0}
.ja-body.open{display:block}
.ja-metrics{display:grid;grid-template-columns:repeat(auto-fill,minmax(100px,1fr));gap:6px;margin-bottom:8px}
.ja-mc{background:#fff;border:1px solid #e5e7eb;border-radius:5px;padding:7px}
.ja-ml{font-size:9px;color:#9ca3af;margin-bottom:2px}
.ja-mv{font-size:14px;font-weight:700}

/* ════════════════════════════════════
   OPTION 3 — JOURNEY ATLAS
════════════════════════════════════ */
.jt-shell{display:flex}
.jt-nav{width:196px;border-right:1px solid #f0f0f0;padding:14px 0;flex-shrink:0}
.jt-main{flex:1}

.tl-header{padding:18px 22px 14px;border-bottom:1px solid #f0f0f0;background:#fafafa}
.tl-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:14px}
.tl-scenario{font-size:13px;font-weight:700;color:#111827}
.tl-total-time{font-size:11px;color:#6b7280}
.tl-total-time strong{color:#c7000b}

.tl-steps{display:flex;position:relative;align-items:flex-start}
.tl-line{position:absolute;top:20px;left:20px;right:20px;height:2px;background:#e5e7eb;z-index:0}
.tl-step{flex:1;display:flex;flex-direction:column;align-items:center;position:relative;z-index:1;cursor:pointer}
.tl-dot{width:40px;height:40px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;border:2px solid transparent;margin-bottom:5px;transition:transform .15s,box-shadow .15s;flex-shrink:0}
.tl-step:hover .tl-dot{transform:scale(1.1)}
.tl-dot.td-r{background:#fef2f2;color:#c7000b;border-color:#fecaca}
.tl-dot.td-y{background:#fffbeb;color:#b45309;border-color:#fde68a}
.tl-dot.td-g{background:#f0fdf4;color:#15803d;border-color:#bbf7d0}
.tl-dot.act{box-shadow:0 0 0 4px rgba(199,0,11,.15)}
.tl-dot.act.td-r{background:#c7000b;color:#fff}
.tl-dot.act.td-y{background:#b45309;color:#fff}
.tl-dot.act.td-g{background:#15803d;color:#fff}
.tl-meta{text-align:center;max-width:72px}
.tl-name{font-size:10px;font-weight:600;color:#6b7280;line-height:1.3;margin-bottom:2px}
.tl-name.act{color:#c7000b}
.tl-time-pct{font-size:9px;color:#9ca3af}
.tl-drop{font-size:9px;font-weight:600}
.tl-drop.bad{color:#c7000b}
.tl-drop.ok{color:#15803d}

.step-detail{padding:20px 22px}
.sd-summary{border-radius:8px;padding:12px 15px;margin-bottom:14px;font-size:13px;color:#374151;line-height:1.65}
.sd-sum-r{background:#fef2f2;border:1px solid #fecaca}
.sd-sum-y{background:#fffbeb;border:1px solid #fde68a}
.sd-sum-g{background:#f0fdf4;border:1px solid #bbf7d0}
.sd-summary strong.r{color:#c7000b}
.sd-summary strong.y{color:#b45309}
.sd-summary strong.g{color:#15803d}

.sd-kpis{display:grid;grid-template-columns:repeat(auto-fill,minmax(110px,1fr));gap:8px;margin-bottom:14px}
.sd-kpi{background:#fff;border:1px solid #e5e7eb;border-radius:7px;padding:10px}
.sd-kpi-l{font-size:10px;color:#9ca3af;margin-bottom:3px;line-height:1.3}
.sd-kpi-v{font-size:18px;font-weight:700}
.sd-kpi-t{font-size:10px;margin-top:2px}

.status-list{margin-bottom:14px;display:flex;flex-direction:column;gap:5px}
.sl-row{display:flex;align-items:center;gap:8px;background:#fff;border:1px solid #f0f0f0;border-radius:6px;padding:7px 10px}
.sl-label{font-size:11px;color:#374151;font-weight:500;min-width:140px}
.sl-track{flex:1;height:4px;background:#f0f0f0;border-radius:2px;overflow:hidden}
.sl-fill{height:100%;border-radius:2px}
.sl-fill.ok{background:#22c55e}.sl-fill.warn{background:#f59e0b}.sl-fill.crit{background:#c7000b}
.sl-val{font-size:12px;font-weight:700;min-width:40px;text-align:right}
.sl-val.ok{color:#15803d}.sl-val.warn{color:#b45309}.sl-val.crit{color:#c7000b}
.sl-badge{font-size:10px;font-weight:700;padding:2px 7px;border-radius:8px;min-width:32px;text-align:center}
.sl-badge.ok{background:#f0fdf4;color:#15803d}
.sl-badge.warn{background:#fffbeb;color:#b45309}
.sl-badge.crit{background:#fef2f2;color:#c7000b}

.sd-row2{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:14px}
.sd-card{background:#fafafa;border:1px solid #e5e7eb;border-radius:8px;padding:13px}
.sd-card-lbl{font-size:10px;font-weight:700;color:#9ca3af;text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px}
.sd-pain{font-size:12px;color:#374151;line-height:1.55;border-left:3px solid #c7000b;padding-left:8px;margin-bottom:5px}
.sd-pain-meta{font-size:10px;color:#9ca3af}
.sd-pain-tags{display:flex;gap:4px;margin-top:4px;flex-wrap:wrap}
.sd-vod{font-size:11px;color:#374151;line-height:1.6;border-left:3px solid #f59e0b;padding-left:8px}
.sd-vod::before{content:'\201C';color:#f59e0b;font-weight:700;font-size:13px}
.sd-vod-meta{font-size:10px;color:#9ca3af;margin-top:3px}
.sd-vol{display:inline-block;background:#fef2f2;color:#c7000b;font-size:10px;font-weight:700;padding:1px 6px;border-radius:8px;margin-top:4px}

.tool-chain{display:flex;flex-wrap:wrap;align-items:center;gap:4px;margin-bottom:14px}
.tool-chip{display:flex;align-items:center;gap:4px;padding:4px 9px;border-radius:16px;font-size:11px;font-weight:500;border:1px solid #e5e7eb;background:#fff}
.tool-ok{border-color:#bbf7d0;background:#f0fdf4;color:#15803d}
.tool-warn{border-color:#fde68a;background:#fffbeb;color:#b45309}

