function selStep(i) {
  for(let j=0;j<5;j++){
    const dot=document.getElementById('td'+j), nm=document.getElementById('tn'+j);
    dot.className='tl-dot '+dotCls[j]+(j===i?' act':'');
    nm.className='tl-name'+(j===i?' act':'');
  }
  const d=steps[i];
  let metricsHtml='';
  if(d.type==='kpi'){
    metricsHtml=`<div class="sd-kpis">${d.kpis.map(k=>`<div class="sd-kpi"><div class="sd-kpi-l">${k.l}</div><div class="sd-kpi-v ${k.c}">${k.v}</div><div class="sd-kpi-t ${k.c==='bad'?'trend-dn':k.c==='ok'?'trend-up':'trend-flat'}">${k.t}</div></div>`).join('')}</div>`;
  } else {
    const sl={'ok':'达标','warn':'警告','crit':'严重'};
    metricsHtml=`<div class="status-list">${d.statusItems.map(s=>`<div class="sl-row"><span class="sl-label">${s.l}</span><div class="sl-track"><div class="sl-fill ${s.s}" style="width:${s.pct}%"></div></div><span class="sl-val ${s.s}">${s.v}</span><span class="sl-badge ${s.s}">${sl[s.s]}</span></div>`).join('')}</div>`;
  }
  const toolsHtml=d.tools?`<div class="sec-label">工具调用链 · 括号内为调用成功率</div><div class="tool-chain">${d.tools.map((t,ti)=>`${ti?'<span class="tool-arrow">→</span>':''}<div class="tool-chip ${t.cls}">${t.name} <span class="tool-rate">${t.rate}</span></div>`).join('')}</div>`:'';
  document.getElementById('stepDetail').innerHTML=`
    <div class="sd-summary ${d.sumCls}">${d.sumStr}</div>
    <div class="sec-label">步骤指标（近 7 次均值）</div>
    ${metricsHtml}
    ${toolsHtml}
    <div class="sd-row2">
      <div class="sd-card"><div class="sd-card-lbl">大客户痛点</div><div class="sd-pain">${d.pain}</div><div class="sd-pain-meta">${d.painMeta}</div></div>
      <div class="sd-card"><div class="sd-card-lbl">VOD 原声</div><div class="sd-vod">${d.vod}</div><div class="sd-vod-meta">${d.vodMeta}</div><div class="sd-vol">${d.vol}</div></div>
    </div>`;
}
selStep(0);
